import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const animateLight = () => {
      const lightElement = document.getElementById("light"); // ✅ ดึง element ใน SVG
      if (lightElement) {
        lightElement.style.fill =
          lightElement.style.fill === "rgb(231, 229, 213)" // #e7e5d5
            ? "#ffe966"
            : "#e7e5d5";
      }
    };

    const interval = setInterval(animateLight, 2000);
    return () => clearInterval(interval); // ✅ ล้าง interval เมื่อออกจากหน้านี้
  }, []);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* ✅ ใช้ <img> เพื่อโหลดไฟล์ photoautomat.svg */}
      <img src="/photoautomat.svg" alt="Photobooth" className="photoautomat-svg" />

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
